import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine().trim(); // Read a line of input and trim any leading/trailing spaces

        // Validate input length to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum length. Please enter a name with 10 characters or less.");
            return;
        }

        // Use proper array initialization and copying to avoid buffer overflow
        byte[] buffer = Arrays.copyOf(name.getBytes(), 10); // Copy up to 10 bytes of input

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any extra bytes from the buffer
    }
}

